class Solution:
    def resultArray(self, nums, k, queries):
        arr = list(nums)
        ans = []
        for idx, val, start, x in queries:
            arr[idx] = val
            count = 0
            prod = 1
            for j in range(start, len(arr)):
                prod = (prod * arr[j]) % k
                if prod == x:
                    count += 1
            ans.append(count)
        return ans

