var resultArray = function(nums, k, queries) {
    const n = nums.length;
    let size = 1;
    while (size < n) size *= 2;
    const hist = new Array(2 * size);
    const prod = new Array(2 * size).fill(1 % k);
    for (let i = 0; i < 2 * size; i++) hist[i] = new Array(k).fill(0);
    const makeLeaf = (v) => { const r = ((v % k) + k) % k; const h = new Array(k).fill(0); h[r]++; return [h, r]; };
    const merge = (lh, lp, rh, rp) => {
        const h = lh.slice();
        for (let rem = 0; rem < k; rem++) if (rh[rem]) h[(lp * rem) % k] += rh[rem];
        return [h, (lp * rp) % k];
    };
    for (let i = 0; i < n; i++) { const [h, p] = makeLeaf(nums[i]); hist[size + i] = h; prod[size + i] = p; }
    for (let i = size - 1; i >= 1; i--) { const [h, p] = merge(hist[2*i], prod[2*i], hist[2*i+1], prod[2*i+1]); hist[i] = h; prod[i] = p; }
    const update = (pos, v) => {
        let i = size + pos;
        const [h, p] = makeLeaf(v); hist[i] = h; prod[i] = p; i = Math.floor(i / 2);
        while (i >= 1) { const [hh, pp] = merge(hist[2*i], prod[2*i], hist[2*i+1], prod[2*i+1]); hist[i] = hh; prod[i] = pp; i = Math.floor(i / 2); }
    };
    const query = (start) => {
        let l = size + start, r = size + n - 1 + 1;
        const leftNodes = [], rightNodes = [];
        while (l < r) {
            if (l & 1) { leftNodes.push(l); l++; }
            if (r & 1) { r--; rightNodes.push(r); }
            l = Math.floor(l / 2); r = Math.floor(r / 2);
        }
        const ordered = leftNodes.concat(rightNodes.reverse());
        let accH = new Array(k).fill(0), accP = 1 % k, first = true;
        for (const node of ordered) {
            if (first) { accH = hist[node].slice(); accP = prod[node]; first = false; }
            else { const [hh, pp] = merge(accH, accP, hist[node], prod[node]); accH = hh; accP = pp; }
        }
        return accH;
    };
    const ans = [];
    for (const [idx, val, start, x] of queries) { update(idx, val); const h = query(start); ans.push(h[x]); }
    return ans;
};
